import os
import hashlib
import json
from datetime import datetime
from flask import Flask, request, jsonify
import numpy as np
from typing import Any, Dict
import tempfile
import shutil

app = Flask(__name__)

UPLOAD_FOLDER = 'models'
ALLOWED_EXTENSIONS = {'pkl', 'pickle', 'joblib'}
MAX_FILE_SIZE = 100 * 1024 * 1024  # 100MB

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

model_registry = {}


class SafeUnpickler:
    """Safe unpickler that only allows specific types"""
    ALLOWED_MODULES = {
        'numpy',
        'numpy.core',
        'numpy.core.multiarray',
        'numpy.core.numeric',
        'numpy.dtype',
        'sklearn',
        'sklearn.tree',
        'sklearn.ensemble',
        'sklearn.linear_model',
        'sklearn.svm',
        'sklearn.naive_bayes',
        'sklearn.neighbors',
        'sklearn.neural_network',
        'xgboost',
        'lightgbm',
        'catboost',
    }
    
    ALLOWED_CLASSES = {
        'numpy.ndarray',
        'numpy.dtype',
        'sklearn.tree._classes.DecisionTreeClassifier',
        'sklearn.tree._classes.DecisionTreeRegressor',
        'sklearn.ensemble._forest.RandomForestClassifier',
        'sklearn.ensemble._forest.RandomForestRegressor',
        'sklearn.linear_model._logistic.LogisticRegression',
        'sklearn.linear_model._base.LinearRegression',
        'sklearn.svm._classes.SVC',
        'sklearn.svm._classes.SVR',
    }

    @staticmethod
    def restricted_loads(data):
        """Load pickle data with restrictions"""
        import pickle
        import io
        
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                full_name = f"{module}.{name}"
                
                if module.split('.')[0] not in SafeUnpickler.ALLOWED_MODULES:
                    raise pickle.UnpicklingError(
                        f"Module '{module}' is not allowed for security reasons"
                    )
                
                if full_name in SafeUnpickler.ALLOWED_CLASSES or module in SafeUnpickler.ALLOWED_MODULES:
                    return super().find_class(module, name)
                
                raise pickle.UnpicklingError(
                    f"Class '{full_name}' is not allowed for security reasons"
                )
        
        return RestrictedUnpickler(io.BytesIO(data)).load()


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_model(model_obj):
    """Validate that the loaded object is a valid ML model"""
    required_methods = ['predict']
    
    for method in required_methods:
        if not hasattr(model_obj, method):
            return False, f"Model must have '{method}' method"
    
    return True, "Valid model"


def calculate_file_hash(file_path):
    """Calculate SHA256 hash of file"""
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()


@app.route('/upload', methods=['POST'])
def upload_model():
    """Upload and register a new model with security checks"""
    try:
        if 'model' not in request.files:
            return jsonify({'error': 'No model file provided'}), 400
        
        file = request.files['model']
        model_name = request.form.get('model_name', '')
        tenant_id = request.form.get('tenant_id', '')
        
        if not model_name or not tenant_id:
            return jsonify({'error': 'model_name and tenant_id are required'}), 400
        
        if file.filename == '':
            return jsonify({'error': 'No selected file'}), 400
        
        if not allowed_file(file.filename):
            return jsonify({'error': f'File type not allowed. Allowed types: {ALLOWED_EXTENSIONS}'}), 400
        
        temp_dir = tempfile.mkdtemp()
        try:
            temp_path = os.path.join(temp_dir, file.filename)
            file.save(temp_path)
            
            file_size = os.path.getsize(temp_path)
            if file_size > MAX_FILE_SIZE:
                return jsonify({'error': f'File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes'}), 400
            
            file_hash = calculate_file_hash(temp_path)
            
            with open(temp_path, 'rb') as f:
                model_data = f.read()
            
            try:
                model = SafeUnpickler.restricted_loads(model_data)
            except Exception as e:
                return jsonify({'error': f'Failed to load model safely: {str(e)}'}), 400
            
            is_valid, message = validate_model(model)
            if not is_valid:
                return jsonify({'error': f'Invalid model: {message}'}), 400
            
            model_id = f"{tenant_id}_{model_name}_{file_hash[:8]}"
            
            final_path = os.path.join(UPLOAD_FOLDER, f"{model_id}.pkl")
            shutil.copy(temp_path, final_path)
            
            model_registry[model_id] = {
                'model': model,
                'tenant_id': tenant_id,
                'model_name': model_name,
                'file_hash': file_hash,
                'upload_time': datetime.now().isoformat(),
                'file_path': final_path
            }
            
            return jsonify({
                'message': 'Model uploaded successfully',
                'model_id': model_id,
                'file_hash': file_hash
            }), 201
            
        finally:
            shutil.rmtree(temp_dir, ignore_errors=True)
            
    except Exception as e:
        return jsonify({'error': f'Upload failed: {str(e)}'}), 500


@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    """Make predictions using a registered model"""
    try:
        if model_id not in model_registry:
            return jsonify({'error': 'Model not found'}), 404
        
        tenant_id = request.headers.get('X-Tenant-ID', '')
        if tenant_id != model_registry[model_id]['tenant_id']:
            return jsonify({'error': 'Unauthorized access to model'}), 403
        
        data = request.get_json()
        if not data or 'input' not in data:
            return jsonify({'error': 'No input data provided'}), 400
        
        input_data = np.array(data['input'])
        
        model = model_registry[model_id]['model']
        predictions = model.predict(input_data)
        
        return jsonify({
            'model_id': model_id,
            'predictions': predictions.tolist()
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 500


@app.route('/models', methods=['GET'])
def list_models():
    """List all registered models for a tenant"""
    try:
        tenant_id = request.headers.get('X-Tenant-ID', '')
        
        if not tenant_id:
            return jsonify({'error': 'X-Tenant-ID header required'}), 400
        
        tenant_models = {
            model_id: {
                'model_name': info['model_name'],
                'upload_time': info['upload_time'],
                'file_hash': info['file_hash']
            }
            for model_id, info in model_registry.items()
            if info['tenant_id'] == tenant_id
        }
        
        return jsonify({'models': tenant_models}), 200
        
    except Exception as e:
        return jsonify({'error': f'Failed to list models: {str(e)}'}), 500


@app.route('/models/<model_id>', methods=['DELETE'])
def delete_model(model_id):
    """Delete a registered model"""
    try:
        if model_id not in model_registry:
            return jsonify({'error': 'Model not found'}), 404
        
        tenant_id = request.headers.get('X-Tenant-ID', '')
        if tenant_id != model_registry[model_id]['tenant_id']:
            return jsonify({'error': 'Unauthorized access to model'}), 403
        
        file_path = model_registry[model_id]['file_path']
        if os.path.exists(file_path):
            os.remove(file_path)
        
        del model_registry[model_id]
        
        return jsonify({'message': 'Model deleted successfully'}), 200
        
    except Exception as e:
        return jsonify({'error': f'Failed to delete model: {str(e)}'}), 500


@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({'status': 'healthy', 'models_loaded': len(model_registry)}), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)